use std::collections::HashMap;

struct LocationInfo {
    line: usize,
    column: usize,
}

fn process_source_locations(pairs: Vec<(usize, usize)>) -> (Vec<usize>, Vec<usize>) {
    let unzipped: (Vec<usize>, Vec<usize>) = pairs.into_iter().unzip();
    (unzipped.0, unzipped.1)
}

fn main() {
    let raw_pairs = vec![(10, 5), (20, 1), (30, 8)];
    let (lines, columns) = process_source_locations(raw_pairs);

    println!("Processed Lines: {:?}", lines);
    println!("Processed Columns: {:?}", columns);
}

use std::collections::HashMap;

struct TaskEstimate(String, u32);

impl TaskEstimate {
    fn into_tuple(self) -> (String, u32) {
        (self.0, self.1)
    }
}

fn main() {
    let tasks = vec![
        TaskEstimate("Login screen".to_string(), 10),
        TaskEstimate("API endpoint".to_string(), 5),
        TaskEstimate("Testing suite".to_string(), 8),
    ];

    let unzipped: Vec<(String, u32)> = tasks.into_iter().map(|task| task.into_tuple()).collect();

    let (names, hours): (Vec<String>, Vec<u32>) = unzipped.into_iter().unzip();

    println!("--- Task Names ---n");
    for name in names {
        println!("{}", name);
    }

    println!("n--- Estimated Hours ---n");
    for hour in hours {
        println!("{}", hour);
    }
}

