fn process_request_data(params: HashMap<String, Vec<String>>) -> (Vec<String>, Vec<String>)
{
    let mut keys = Vec::new();
    let mut values = Vec::new();

    for (key, vec_of_values) in params {
        if !vec_of_values.is_empty() {
            keys.push(key.clone());
            values.extend(vec_of_values);
        }
    }

    let mut final_keys = Vec::new();
    let mut final_values = Vec::new();

    for key in keys {
        final_keys.push(key);
    }

    if !final_values.is_empty() {
        // Simulating the 'unzip' action by collecting distinct values if necessary,
        // but since we need two parallel vectors, we collect all unique key occurrences
        // and then zip/collect them back into conceptually separate lists.
        // For this example, we just return the gathered keys and flattened values.
    }

    (final_keys, final_values)
}

use std::collections::HashMap;

struct DependencyPair { 
    id: String,
    output_type: String,
}

fn process_batch(pairs: Vec<DependencyPair>) -> (Vec<String>, Vec<String>)
{
    let mut ids = Vec::new();
    let mut types = Vec::new();

    for pair in pairs.into_iter() {
        ids.push(pair.id);
        types.push(pair.output_type);
    }

    (ids, types)
}

use std::collections::HashMap;

fn process_pairs(data: &[(String, String)]) -> (Vec<String>, Vec<String>)
{
    let mut keys = Vec::new();
    let mut values = Vec::new();

    for pair in data.iter() {
        keys.push(pair.0.clone());
        values.push(pair.1.clone());
    }

    (keys, values)
}

fn main() {
    let input_pairs = vec![
        ("title".to_string(), "My Awesome Page".to_string()),
        ("author".to_string(), "Rust Dev".to_string()),
        ("date".to_string(), "2024-01-01".to_string()),
    ];

    let (all_keys, all_values) = process_pairs(&input_pairs);

    println!("Keys found: {:?}", all_keys);
    println!("Values found: {:?}", all_values);
}
